// inputTypeString converts InputType enum to HTML input type string.
func inputTypeString(t InputType) string {
	switch t {
	case InputEmail:
		return "email"
	case InputTel:
		return "tel"
	case InputNumber:
		return "number"
	case InputPassword:
		return "password"
	case InputURL:
		return "url"
	case InputSearch:
		return "search"
	case InputDate:
		return "date"
	case InputDateTimeLocal:
		return "datetime-local"
	default:
		return "text"
	}
}

// inputClass generates the CSS class for the input based on state.
func inputClass(hasError, isDisabled bool, class string) string {
	base := "input"

	var stateClass string
	if hasError {
		stateClass = base + " input--error"
	} else if isDisabled {
		stateClass = base + " input--disabled"
	} else {
		stateClass = base
	}

	if class != "" {
		return stateClass + " " + class
	}
	return stateClass
}

